  const [rfpsAll, passkeysRfps, smartAccountsRfps] = await Promise.all([
    scout.getRfps({ status: "open", limit: 50 }),
    lumenloop.find_similar_scf_submissions({ query: "passkeys smart wallets authentication", limit: 8 }),
    lumenloop.find_similar_scf_submissions({ query: "smart accounts account abstraction", limit: 8 })
  ]);

  const rfpResult = rfpsAll.ok
    ? {
        fetchedAt: new Date().toISOString(),
        total: rfpsAll.data?.rfps?.length ?? 0,
        openRfps: (rfpsAll.data?.rfps ?? []).map(r => ({
          title: r.title,
          status: r.status,
          category: r.category,
          summary: r.summary ?? r.description,
          url: r.url ?? r.link,
          round: r.round,
          deadline: r.deadline
        }))
      }
    : { error: rfpsAll.error };

  // Filter open RFPs for passkey/smart account relevance
  const keywords = ["passkey", "smart account", "account abstraction", "webauthn", "multisig", "wallet", "authentication", "signer"];
  const relevantOpen = (rfpResult.openRfps ?? []).filter(r => {
    const text = `${r.title} ${r.summary} ${r.category}`.toLowerCase();
    return keywords.some(k => text.includes(k));
  });

  return {
    fetchedAt: rfpResult.fetchedAt,
    totalOpenRfps: rfpResult.total,
    relevantOpenRfps: relevantOpen,
    allOpenRfps: rfpResult.openRfps?.slice(0, 20), // show up to 20 for context
    similarScfSubmissions: {
      passkeys: passkeysRfps.ok ? passkeysRfps.data?.submissions?.slice(0, 5).map(s => ({
