  const [zkRepos, zkProofs, zkDocs, sorobanZkDocs] = await Promise.all([
    scout.searchRepos({ query: "zero-knowledge ZK proof Soroban", limit: 10 }),
    scout.searchRepos({ query: "ZK SNARK STARK verifier Stellar", limit: 8 }),
    stellarDocs.search_docs({ query: "zero-knowledge proof Soroban ZK", hitsPerPage: 5 }),
    stellarDocs.search_soroban_contract_docs({ query: "ZK proof verifier cryptography", hitsPerPage: 5 })
  ]);

  const repoRows = (r) => {
    if (!r.ok) return { error: r.error.message };
    const repos = r.data.repos || r.data.results || r.data || [];
    return repos.slice(0, 10).map(repo => ({
      name: repo.name || repo.full_name,
      url: repo.url || repo.html_url,
      description: repo.description,
      language: repo.language,
      stars: repo.stargazers_count ?? repo.stars,
      forks: repo.forks_count ?? repo.forks,
      lastPushed: repo.pushed_at || repo.last_pushed,
      topics: repo.topics,
      score: repo.score ?? repo.quality_score,
      archived: repo.archived
    }));
  };

  const docHits = (r) => {
    if (!r.ok) return { error: r.error.message };
    const hits = r.data.hits || [];
    return hits.slice(0, 4).map(h => ({ title: h.title, url: h.url, snippet: h.snippet }));
  };

  return {
    zkSorobanRepos: repoRows(zkRepos),
    zkProofRepos: repoRows(zkProofs),
    generalDocs: docHits(zkDocs),
    sorobanDocs: docHits(sorobanZkDocs)
  };
}

