  // Search for active projects in the directory
  const dirResult = await lumenloop.search_directory({ query: "active development", limit: 20 });

  if (!dirResult.ok) {
    return { error: dirResult.error };
  }

  const projects = dirResult.data.projects || [];

  // Get detailed info on top projects to check for activity indicators
  const projectDetails = await Promise.all(
    projects.slice(0, 10).map(p => 
      lumenloop.get_project({ slug: p.slug, compact: false })
    )
  );

  // Filter successful results and extract activity indicators
  const activeProjects = projectDetails
    .filter(r => r.ok)
    .map(r => {
      const p = r.data;
      return {
        title: p.title,
        slug: p.slug,
        category: p.category,
        description: p.description,
        website: p.website,
        github_url: p.github_url,
        last_updated: p.last_updated,
        updated_at: p.updated_at,
        created_at: p.created_at,
        activity_indicators: {
          has_github: !!p.github_url,
          last_updated: p.last_updated || p.updated_at,
          created_at: p.created_at
        }
      };
    })
    .sort((a, b) => {
      // Sort by last_updated date (most recent first)
      const dateA = new Date(a.activity_indicators.last_updated || 0);
      const dateB = new Date(b.activity_indicators.last_updated || 0);
      return dateB - dateA;
    })
