async () => {
  // Search for ZK-related Soroban repos
  const zkRepos = await scout.searchRepos({
    query: "ZK zero-knowledge Soroban",
    limit: 20
  });

  // Also search for Soroban contract examples and cryptography
  const sorobanCrypto = await scout.searchRepos({
    query: "Soroban cryptography BLS12-381",
    limit: 15
  });

  // Compile results
  const allRepos = [];

  if (zkRepos.ok && zkRepos.data.repos) {
    allRepos.push(...zkRepos.data.repos);
  }

  if (sorobanCrypto.ok && sorobanCrypto.data.repos) {
    // Deduplicate by URL
    const urls = new Set(allRepos.map(r => r.url));
    sorobanCrypto.data.repos.forEach(r => {
      if (!urls.has(r.url)) {
        allRepos.push(r);
      }
    });
  }

  // Filter for high-signal ZK/crypto repos and sort by activity
  const filtered = allRepos
    .filter(r => r.description && (
      r.description.toLowerCase().includes('zk') ||
      r.description.toLowerCase().includes('zero-knowledge') ||
      r.description.toLowerCase().includes('proof') ||
      r.description.toLowerCase().includes('bls12') ||
      r.description.toLowerCase().includes('cryptograph')
    ))
    .sort((a, b) => {
      // Prioritize by stars and recent activity
      const aScore = (a.stars || 0) + (a.recentCommits ? 10 : 0);
      const bScore = (b.stars || 0) + (b.recentCommits ? 10 : 0);
      return bScore - aScore;
    })
    .slice(0, 10)
    .map(r => ({
      name: r.name,
      owner: r.owner,
      url: r.url,
      description: r.description,
      stars: r.stars || 0,
      language: r.language,
      lastUpdated: r.lastUpdated,
      recentCommits: r.recentCommits || false,
      topics: r.topics ? r.topics.slice(0, 5) : []
    }));

  return {
    totalFound: allRepos.length,
    highSignalRepos: filtered,
    caveat: "Activity status based on indexed GitHub metadata; verify current status and maintenance level directly on GitHub. 'recentCommits' indicates activity within recent indexing window."
  };
}

